/// WebKitSnapshotOptions:
/// @WEBKIT_SNAPSHOT_OPTIONS_NONE: Do not include any special options.
/// @WEBKIT_SNAPSHOT_OPTIONS_INCLUDE_SELECTION_HIGHLIGHTING: Whether to include in the
/// snapshot the highlight of the selected content.
/// @WEBKIT_SNAPSHOT_OPTIONS_TRANSPARENT_BACKGROUND: Do not fill the background with white before
/// rendering the snapshot. Since 2.8
///
/// Enum values used to specify options when taking a snapshot
/// from a #WebKitWebView.
enum WebKitSnapshotOptions {
  WEBKIT_SNAPSHOT_OPTIONS_NONE(0),
  WEBKIT_SNAPSHOT_OPTIONS_INCLUDE_SELECTION_HIGHLIGHTING(1),
  WEBKIT_SNAPSHOT_OPTIONS_TRANSPARENT_BACKGROUND(2);

  final int value;
  const WebKitSnapshotOptions(this.value);

  static WebKitSnapshotOptions fromValue(int value) => switch (value) {
    0 => WEBKIT_SNAPSHOT_OPTIONS_NONE,
    1 => WEBKIT_SNAPSHOT_OPTIONS_INCLUDE_SELECTION_HIGHLIGHTING,
    2 => WEBKIT_SNAPSHOT_OPTIONS_TRANSPARENT_BACKGROUND,
    _ => throw ArgumentError("Unknown value for WebKitSnapshotOptions: $value"),
  };
}

/// WebKitSnapshotRegion:
/// @WEBKIT_SNAPSHOT_REGION_VISIBLE: Specifies a snapshot only for the area that is
/// visible in the webview
/// @WEBKIT_SNAPSHOT_REGION_FULL_DOCUMENT: A snapshot of the entire document.
///
/// Enum values used to specify the region from which to get a #WebKitWebView
/// snapshot
enum WebKitSnapshotRegion {
  WEBKIT_SNAPSHOT_REGION_VISIBLE(0),
  WEBKIT_SNAPSHOT_REGION_FULL_DOCUMENT(1);

  final int value;
  const WebKitSnapshotRegion(this.value);

  static WebKitSnapshotRegion fromValue(int value) => switch (value) {
    0 => WEBKIT_SNAPSHOT_REGION_VISIBLE,
    1 => WEBKIT_SNAPSHOT_REGION_FULL_DOCUMENT,
    _ => throw ArgumentError("Unknown value for WebKitSnapshotRegion: $value"),
  };
}

